mapper.select:
SELECT mn.id, mn.initiator_id, mn.target_user_id, mn.target_vehicle_id, mn.plate_number, mn.notify_type, mn.status, mn.location, mn.parking_info, mn.remark, mn.response_time, mn.complete_time, mn.create_time FROM move_notification mn WHERE mn.deleted = 0 AND ( mn.initiator_id = #{userId} OR mn.target_user_id = #{userId} )
AND mn.status = #{status}
AND mn.notify_type = #{notifyType}
ORDER BY mn.create_time DESC
